package dev.codedefense.cli;import dev.codedefense.application.*;import dev.codedefense.passport.*;import java.nio.file.Path;import java.time.*;import java.util.concurrent.Callable;import picocli.CommandLine.*;
@Command(name="create",mixinStandardHelpOptions=true,description="Create a portable source-free handoff.")public final class PassportHandoffCreateCommand implements Callable<Integer>{@Parameters(index="0",arity="0..1",defaultValue=".")Path repository;@Option(names="--output",required=true,paramLabel="FILE",description="Destination file; name must end with *.cdhandoff.json.")Path output;@Option(names="--overwrite")boolean overwrite;@Spec Model.CommandSpec spec;private final CreateChangeHandoffUseCase useCase;public PassportHandoffCreateCommand(){this(new CreateChangeHandoffUseCase(new FileSystemChangePassportStore(ChangePassportPaths.defaults(),new MarkdownChangePassportRenderer(),Clock.systemUTC()),new ChangeHandoffJsonCodec(),new FileSystemChangeHandoffStore(),Clock.systemUTC(),()->java.util.UUID.randomUUID().toString()));}PassportHandoffCreateCommand(CreateChangeHandoffUseCase u){useCase=u;}public Integer call(){try{return useCase.create(repository,output,overwrite,spec.commandLine().getOut(),spec.commandLine().getErr());}catch(ChangeHandoffPersistenceException|ChangePassportPersistenceException e){spec.commandLine().getErr().println(e.getMessage());return ExitCodes.REPORT_PERSISTENCE_FAILED;}}}
